const { execSync } = require('child_process');
const fs = require('fs');
const item = items[0].json;
const dir = `/workspace/video_assets/${item.video_id}`;
const captionsEnabled = String($env.CAPTIONS_ENABLED || 'false').toLowerCase() === 'true';
if (!captionsEnabled) return [{ json: item }];
const scenes = item.scenes || [];
if (!scenes.length) return [{ json: item }];
let srt = ''; let t = 0;
scenes.forEach((s, i) => {
  const dur = s.duration_seconds || s.duration || 5;
  const ts = d => { const ms = Math.round((d % 1) * 1000); const sec = Math.floor(d) % 60; const min = Math.floor(d / 60) % 60; const hr = Math.floor(d / 3600); return `${String(hr).padStart(2,'0')}:${String(min).padStart(2,'0')}:${String(sec).padStart(2,'0')},${String(ms).padStart(3,'0')}`; };
  srt += `${i+1}\n${ts(t)} --> ${ts(t+dur)}\n${(s.narration||'').substring(0,80)}\n\n`;
  t += dur;
});
try {
  fs.writeFileSync(`${dir}/subs.srt`, srt);
  execSync(`ffmpeg -y -i ${dir}/final_16x9.mp4 -vf "subtitles=${dir}/subs.srt:force_style='FontSize=16,PrimaryColour=&Hffffff,OutlineColour=&H000000,Outline=2'" -c:a copy ${dir}/final_subs.mp4`, { shell: '/bin/bash', timeout: 120000 });
  execSync(`mv ${dir}/final_subs.mp4 ${dir}/final_16x9.mp4`, { shell: '/bin/bash' });
  return [{ json: { ...item, captions_added: true } }];
} catch(e) {
  console.log('Undertekster hoppet over:', e.message);
  return [{ json: { ...item, captions_added: false } }];
}

const { execSync } = require('child_process');
const item = items[0].json;
