  if (ratio === '9:16' || ratio !== '16:9') {
    execSync(`ffmpeg -y -i "${dir}/final_16x9.mp4" -vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2,setsar=1" "${dir}/final_9x16.mp4"`, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
  }
  execSync(`ffmpeg -y -i "${dir}/final_16x9.mp4" -vf "scale=1080:1080:force_original_aspect_ratio=decrease,pad=1080:1080:(ow-iw)/2:(oh-ih)/2,setsar=1" "${dir}/final_1x1.mp4"`, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
  return [{ json: { ...item, video_id: videoId, success: true } }];
} catch(err) {
  throw new Error('FFmpeg scale failed: ' + err.message);
}

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const userId = item.user_id;
const dir = `/workspace/video_assets/${videoId}`;
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const uploads = [
  { file: 'final_16x9.mp4', format: '16x9' },
  { file: 'final_9x16.mp4', format: '9x16' },
  { file: 'final_1x1.mp4',  format: '1x1' },
];
const uploadedUrls = {};
for (const u of uploads) {
  const filePath = `${dir}/${u.file}`;
  const storagePath = `${userId}/${videoId}/${u.file}`;
  try {
    execSync(`curl -sf -X POST "${supabaseUrl}/storage/v1/object/videos/${storagePath}" -H "Authorization: Bearer ${serviceKey}" -H "Content-Type: video/mp4" --data-binary @"${filePath}"`, { encoding: 'utf-8', timeout: 600000, shell: '/bin/bash' });
    uploadedUrls[`video_url_${u.format.replace(':', 'x')}`] = `${supabaseUrl}/storage/v1/object/public/videos/${storagePath}`;
  } catch(err) {
    console.log(`Upload ${u.format} feilet (non-fatal): ${err.message}`);
  }
}
return [{ json: { ...item, video_id: videoId, user_id: userId, ...uploadedUrls } }];

const item = items[0].json;
