parameters.jsCode:
const item = $input.first().json;
const resp = item.choices?.[0]?.message?.content || item.response || item.message?.content || '';
if (!resp) throw new Error('Tom respons fra OpenRouter. Sjekk OPENROUTER_API_KEY.');
let topics = [];
try { topics = JSON.parse(resp); } catch {
  try { const match = resp.match(/\[[\s\S]*\]/); if (match) topics = JSON.parse(match[0]); } catch(e) { throw new Error('Parse error: ' + e.message); }
}
if (!Array.isArray(topics) || !topics.length) throw new Error('Ingen trender returnert.');
const platformMap = { tech: 'youtube', motivation: 'tiktok', history: 'youtube', science: 'youtube', crime: 'tiktok', finance: 'youtube', health: 'instagram', mystery: 'tiktok' };
return topics.map(t => ({ json: {
  title: t.title || 'Ukjent topic',
  category: t.category || 'general',
  viral_score: t.rank || t.viral_score || Math.floor(Math.random() * 40 + 55),
  heat_level: t.heat || t.heat_level || 'rising',
  growth_stat: t.reason || t.growth_stat || null,
  tags: Array.isArray(t.tags) ? t.tags : [],
  platform: t.platform || platformMap[t.category] || 'youtube',
  target_audience: t.target_audience || (t.category ? t.category + ' enthusiasts' : 'General audience'),
} }));

const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const autoOrder = String($env.TREND_AUTO_ORDER || 'false').toLowerCase() === 'true';
if (!autoOrder) return [{ json: { status: 'TREND_AUTO_ORDER not enabled' } }];
function makeUUID() { return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => { const r = Math.random() * 16 | 0; return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16); }); }
const trends = await this.helpers.httpRequest({ method: 'GET', url: `${supabaseUrl}/rest/v1/trending_topics?active=eq.true&order=viral_score.desc&limit=3`, headers: { apikey: serviceKey, Authorization: `Bearer ${serviceKey}` }, json: true });
const results = [];
for (const t of (trends || [])) {
  const videoId = makeUUID();
  await this.helpers.httpRequest({ method: 'POST', url: `${supabaseUrl}/rest/v1/videos`, headers: { apikey: serviceKey, Authorization: `Bearer ${serviceKey}`, 'Content-Type': 'application/json', Prefer: 'return=minimal' }, body: { id: videoId, title: t.title, topic: t.title, status: 'queued', language: 'nb', platform: t.platform || 'youtube', retry_count: 0, views: 0, progress: 0, captions_enabled: true }, json: true });
  results.push({ video_id: videoId, title: t.title });
}
return results.length ? results.map(r => ({ json: r })) : [{ json: { status: 'ingen trender' } }];

const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const cutoff = new Date(Date.now() - 30 * 60 * 1000).toISOString();
const stuck = await this.helpers.httpRequest({ method: 'GET', url: `${supabaseUrl}/rest/v1/videos?status=in.(queued,scripting,recording,editing)&updated_at=lt.${cutoff}&limit=10`, headers: { apikey: serviceKey, Authorization: `Bearer ${serviceKey}` }, json: true });
const results = [];
for (const v of (stuck || [])) {
  const retries = (v.retry_count || 0) + 1;
  const newStatus = retries > 3 ? 'failed' : 'queued';
  await this.helpers.httpRequest({ method: 'PATCH', url: `${supabaseUrl}/rest/v1/videos?id=eq.${v.id}`, headers: { apikey: serviceKey, Authorization: `Bearer ${serviceKey}`, 'Content-Type': 'application/json', Prefer: 'return=minimal' }, body: { status: newStatus, retry_count: retries, sub_status: newStatus === 'failed' ? 'Feilet etter 3 forsøk' : `Auto-retry #${retries}` }, json: true });
  await this.helpers.httpRequest({ method: 'POST', url: `${supabaseUrl}/rest/v1/agent_logs`, headers: { apikey: serviceKey, Authorization: `Bearer ${serviceKey}`, 'Content-Type': 'application/json', Prefer: 'return=minimal' }, body: { agent_id: 'watchdog', action: `Video ${newStatus === 'failed' ? 'markert failed etter 3 forsøk' : `rekøet (forsøk #${retries})`}: ${v.title || v.id}`, status: 'ok', video_id: v.id }, json: true });
  results.push({ id: v.id, new_status: newStatus, attempt: retries });
}
return results.length ? results.map(r => ({ json: r })) : [{ json: { status: 'ingen saker', checked_at: new Date().toISOString() } }];

const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const groqKey = $env.GROQ_API_KEY;
if (!groqKey) return [{ json: { status: 'GROQ_API_KEY mangler' } }];
const comments = await this.helpers.httpRequest({ method: 'GET', url: `${supabaseUrl}/rest/v1/comments?replied=eq.false&limit=10`, headers: { apikey: serviceKey, Authorization: `Bearer ${serviceKey}` }, json: true });
const results = [];
for (const c of (comments || [])) {
  try {
    const r = await this.helpers.httpRequest({ method: 'POST', url: 'https://api.groq.com/openai/v1/chat/completions', headers: { Authorization: `Bearer ${groqKey}`, 'Content-Type': 'application/json' }, body: { model: 'llama-3.1-8b-instant', messages: [{ role: 'system', content: 'Svar kort og vennlig. Maks 2 setninger. Match språket i kommentaren.' }, { role: 'user', content: 'Kommentar: ' + c.text }], max_tokens: 100 }, json: true });
    const reply = r.choices?.[0]?.message?.content || '';
    await this.helpers.httpRequest({ method: 'PATCH', url: `${supabaseUrl}/rest/v1/comments?id=eq.${c.id}`, headers: { apikey: serviceKey, Authorization: `Bearer ${serviceKey}`, 'Content-Type': 'application/json', Prefer: 'return=minimal' }, body: { replied: true, reply_text: reply }, json: true });
    await this.helpers.httpRequest({ method: 'POST', url: `${supabaseUrl}/rest/v1/agent_logs`, headers: { apikey: serviceKey, Authorization: `Bearer ${serviceKey}`, 'Content-Type': 'application/json', Prefer: 'return=minimal' }, body: { agent_id: 'SocialResponse', action: `Svarte på kommentar fra ${c.author || 'ukjent'}`, status: 'ok', details: { reply: reply.substring(0, 100) } }, json: true });
    results.push({ id: c.id, reply });
  } catch(e) { results.push({ id: c.id, error: e.message }); }
}
return results.length ? results.map(r => ({ json: r })) : [{ json: { status: 'ingen nye kommentarer' } }];
